{"version":3,"sources":["../../../../node_modules/date-fns/isSameWeek.js","../../../../node_modules/date-fns/locale/uk/_lib/formatDistance.js","../../../../node_modules/date-fns/locale/uk/_lib/formatLong.js","../../../../node_modules/date-fns/locale/uk/_lib/formatRelative.js","../../../../node_modules/date-fns/locale/uk/_lib/localize.js","../../../../node_modules/date-fns/locale/uk/_lib/match.js","../../../../node_modules/date-fns/locale/uk.js"],"sourcesContent":["import { normalizeDates } from \"./_lib/normalizeDates.js\";\nimport { startOfWeek } from \"./startOfWeek.js\";\n\n/**\n * The {@link isSameWeek} function options.\n */\n\n/**\n * @name isSameWeek\n * @category Week Helpers\n * @summary Are the given dates in the same week (and month and year)?\n *\n * @description\n * Are the given dates in the same week (and month and year)?\n *\n * @param laterDate - The first date to check\n * @param earlierDate - The second date to check\n * @param options - An object with options\n *\n * @returns The dates are in the same week (and month and year)\n *\n * @example\n * // Are 31 August 2014 and 4 September 2014 in the same week?\n * const result = isSameWeek(new Date(2014, 7, 31), new Date(2014, 8, 4))\n * //=> true\n *\n * @example\n * // If week starts with Monday,\n * // are 31 August 2014 and 4 September 2014 in the same week?\n * const result = isSameWeek(new Date(2014, 7, 31), new Date(2014, 8, 4), {\n *   weekStartsOn: 1\n * })\n * //=> false\n *\n * @example\n * // Are 1 January 2014 and 1 January 2015 in the same week?\n * const result = isSameWeek(new Date(2014, 0, 1), new Date(2015, 0, 1))\n * //=> false\n */\nexport function isSameWeek(laterDate, earlierDate, options) {\n  const [laterDate_, earlierDate_] = normalizeDates(\n    options?.in,\n    laterDate,\n    earlierDate,\n  );\n  return (\n    +startOfWeek(laterDate_, options) === +startOfWeek(earlierDate_, options)\n  );\n}\n\n// Fallback for modularized imports:\nexport default isSameWeek;\n","function declension(scheme, count) {\n  // scheme for count=1 exists\n  if (scheme.one !== undefined && count === 1) {\n    return scheme.one;\n  }\n\n  const rem10 = count % 10;\n  const rem100 = count % 100;\n\n  // 1, 21, 31, ...\n  if (rem10 === 1 && rem100 !== 11) {\n    return scheme.singularNominative.replace(\"{{count}}\", String(count));\n\n    // 2, 3, 4, 22, 23, 24, 32 ...\n  } else if (rem10 >= 2 && rem10 <= 4 && (rem100 < 10 || rem100 > 20)) {\n    return scheme.singularGenitive.replace(\"{{count}}\", String(count));\n\n    // 5, 6, 7, 8, 9, 10, 11, ...\n  } else {\n    return scheme.pluralGenitive.replace(\"{{count}}\", String(count));\n  }\n}\n\nfunction buildLocalizeTokenFn(scheme) {\n  return (count, options) => {\n    if (options && options.addSuffix) {\n      if (options.comparison && options.comparison > 0) {\n        if (scheme.future) {\n          return declension(scheme.future, count);\n        } else {\n          return \"蟹邪 \" + declension(scheme.regular, count);\n        }\n      } else {\n        if (scheme.past) {\n          return declension(scheme.past, count);\n        } else {\n          return declension(scheme.regular, count) + \" 褌芯屑褍\";\n        }\n      }\n    } else {\n      return declension(scheme.regular, count);\n    }\n  };\n}\n\nconst halfAtMinute = (_, options) => {\n  if (options && options.addSuffix) {\n    if (options.comparison && options.comparison > 0) {\n      return \"蟹邪 锌褨胁褏胁懈谢懈薪懈\";\n    } else {\n      return \"锌褨胁褏胁懈谢懈薪懈 褌芯屑褍\";\n    }\n  }\n\n  return \"锌褨胁褏胁懈谢懈薪懈\";\n};\n\nconst formatDistanceLocale = {\n  lessThanXSeconds: buildLocalizeTokenFn({\n    regular: {\n      one: \"屑械薪褕械 褋械泻褍薪写懈\",\n      singularNominative: \"屑械薪褕械 {{count}} 褋械泻褍薪写懈\",\n      singularGenitive: \"屑械薪褕械 {{count}} 褋械泻褍薪写\",\n      pluralGenitive: \"屑械薪褕械 {{count}} 褋械泻褍薪写\",\n    },\n    future: {\n      one: \"屑械薪褕械, 薪褨卸 蟹邪 褋械泻褍薪写褍\",\n      singularNominative: \"屑械薪褕械, 薪褨卸 蟹邪 {{count}} 褋械泻褍薪写褍\",\n      singularGenitive: \"屑械薪褕械, 薪褨卸 蟹邪 {{count}} 褋械泻褍薪写懈\",\n      pluralGenitive: \"屑械薪褕械, 薪褨卸 蟹邪 {{count}} 褋械泻褍薪写\",\n    },\n  }),\n\n  xSeconds: buildLocalizeTokenFn({\n    regular: {\n      singularNominative: \"{{count}} 褋械泻褍薪写邪\",\n      singularGenitive: \"{{count}} 褋械泻褍薪写懈\",\n      pluralGenitive: \"{{count}} 褋械泻褍薪写\",\n    },\n    past: {\n      singularNominative: \"{{count}} 褋械泻褍薪写褍 褌芯屑褍\",\n      singularGenitive: \"{{count}} 褋械泻褍薪写懈 褌芯屑褍\",\n      pluralGenitive: \"{{count}} 褋械泻褍薪写 褌芯屑褍\",\n    },\n    future: {\n      singularNominative: \"蟹邪 {{count}} 褋械泻褍薪写褍\",\n      singularGenitive: \"蟹邪 {{count}} 褋械泻褍薪写懈\",\n      pluralGenitive: \"蟹邪 {{count}} 褋械泻褍薪写\",\n    },\n  }),\n\n  halfAMinute: halfAtMinute,\n\n  lessThanXMinutes: buildLocalizeTokenFn({\n    regular: {\n      one: \"屑械薪褕械 褏胁懈谢懈薪懈\",\n      singularNominative: \"屑械薪褕械 {{count}} 褏胁懈谢懈薪懈\",\n      singularGenitive: \"屑械薪褕械 {{count}} 褏胁懈谢懈薪\",\n      pluralGenitive: \"屑械薪褕械 {{count}} 褏胁懈谢懈薪\",\n    },\n    future: {\n      one: \"屑械薪褕械, 薪褨卸 蟹邪 褏胁懈谢懈薪褍\",\n      singularNominative: \"屑械薪褕械, 薪褨卸 蟹邪 {{count}} 褏胁懈谢懈薪褍\",\n      singularGenitive: \"屑械薪褕械, 薪褨卸 蟹邪 {{count}} 褏胁懈谢懈薪懈\",\n      pluralGenitive: \"屑械薪褕械, 薪褨卸 蟹邪 {{count}} 褏胁懈谢懈薪\",\n    },\n  }),\n\n  xMinutes: buildLocalizeTokenFn({\n    regular: {\n      singularNominative: \"{{count}} 褏胁懈谢懈薪邪\",\n      singularGenitive: \"{{count}} 褏胁懈谢懈薪懈\",\n      pluralGenitive: \"{{count}} 褏胁懈谢懈薪\",\n    },\n    past: {\n      singularNominative: \"{{count}} 褏胁懈谢懈薪褍 褌芯屑褍\",\n      singularGenitive: \"{{count}} 褏胁懈谢懈薪懈 褌芯屑褍\",\n      pluralGenitive: \"{{count}} 褏胁懈谢懈薪 褌芯屑褍\",\n    },\n    future: {\n      singularNominative: \"蟹邪 {{count}} 褏胁懈谢懈薪褍\",\n      singularGenitive: \"蟹邪 {{count}} 褏胁懈谢懈薪懈\",\n      pluralGenitive: \"蟹邪 {{count}} 褏胁懈谢懈薪\",\n    },\n  }),\n\n  aboutXHours: buildLocalizeTokenFn({\n    regular: {\n      singularNominative: \"斜谢懈蟹褜泻芯 {{count}} 谐芯写懈薪懈\",\n      singularGenitive: \"斜谢懈蟹褜泻芯 {{count}} 谐芯写懈薪\",\n      pluralGenitive: \"斜谢懈蟹褜泻芯 {{count}} 谐芯写懈薪\",\n    },\n    future: {\n      singularNominative: \"锌褉懈斜谢懈蟹薪芯 蟹邪 {{count}} 谐芯写懈薪褍\",\n      singularGenitive: \"锌褉懈斜谢懈蟹薪芯 蟹邪 {{count}} 谐芯写懈薪懈\",\n      pluralGenitive: \"锌褉懈斜谢懈蟹薪芯 蟹邪 {{count}} 谐芯写懈薪\",\n    },\n  }),\n\n  xHours: buildLocalizeTokenFn({\n    regular: {\n      singularNominative: \"{{count}} 谐芯写懈薪褍\",\n      singularGenitive: \"{{count}} 谐芯写懈薪懈\",\n      pluralGenitive: \"{{count}} 谐芯写懈薪\",\n    },\n  }),\n\n  xDays: buildLocalizeTokenFn({\n    regular: {\n      singularNominative: \"{{count}} 写械薪褜\",\n      singularGenitive: \"{{count}} 写薪i\",\n      pluralGenitive: \"{{count}} 写薪褨胁\",\n    },\n  }),\n\n  aboutXWeeks: buildLocalizeTokenFn({\n    regular: {\n      singularNominative: \"斜谢懈蟹褜泻芯 {{count}} 褌懈卸薪褟\",\n      singularGenitive: \"斜谢懈蟹褜泻芯 {{count}} 褌懈卸薪褨胁\",\n      pluralGenitive: \"斜谢懈蟹褜泻芯 {{count}} 褌懈卸薪褨胁\",\n    },\n    future: {\n      singularNominative: \"锌褉懈斜谢懈蟹薪芯 蟹邪 {{count}} 褌懈卸写械薪褜\",\n      singularGenitive: \"锌褉懈斜谢懈蟹薪芯 蟹邪 {{count}} 褌懈卸薪褨\",\n      pluralGenitive: \"锌褉懈斜谢懈蟹薪芯 蟹邪 {{count}} 褌懈卸薪褨胁\",\n    },\n  }),\n\n  xWeeks: buildLocalizeTokenFn({\n    regular: {\n      singularNominative: \"{{count}} 褌懈卸写械薪褜\",\n      singularGenitive: \"{{count}} 褌懈卸薪褨\",\n      pluralGenitive: \"{{count}} 褌懈卸薪褨胁\",\n    },\n  }),\n\n  aboutXMonths: buildLocalizeTokenFn({\n    regular: {\n      singularNominative: \"斜谢懈蟹褜泻芯 {{count}} 屑褨褋褟褑褟\",\n      singularGenitive: \"斜谢懈蟹褜泻芯 {{count}} 屑褨褋褟褑褨胁\",\n      pluralGenitive: \"斜谢懈蟹褜泻芯 {{count}} 屑褨褋褟褑褨胁\",\n    },\n    future: {\n      singularNominative: \"锌褉懈斜谢懈蟹薪芯 蟹邪 {{count}} 屑褨褋褟褑褜\",\n      singularGenitive: \"锌褉懈斜谢懈蟹薪芯 蟹邪 {{count}} 屑褨褋褟褑褨\",\n      pluralGenitive: \"锌褉懈斜谢懈蟹薪芯 蟹邪 {{count}} 屑褨褋褟褑褨胁\",\n    },\n  }),\n\n  xMonths: buildLocalizeTokenFn({\n    regular: {\n      singularNominative: \"{{count}} 屑褨褋褟褑褜\",\n      singularGenitive: \"{{count}} 屑褨褋褟褑褨\",\n      pluralGenitive: \"{{count}} 屑褨褋褟褑褨胁\",\n    },\n  }),\n\n  aboutXYears: buildLocalizeTokenFn({\n    regular: {\n      singularNominative: \"斜谢懈蟹褜泻芯 {{count}} 褉芯泻褍\",\n      singularGenitive: \"斜谢懈蟹褜泻芯 {{count}} 褉芯泻褨胁\",\n      pluralGenitive: \"斜谢懈蟹褜泻芯 {{count}} 褉芯泻褨胁\",\n    },\n    future: {\n      singularNominative: \"锌褉懈斜谢懈蟹薪芯 蟹邪 {{count}} 褉褨泻\",\n      singularGenitive: \"锌褉懈斜谢懈蟹薪芯 蟹邪 {{count}} 褉芯泻懈\",\n      pluralGenitive: \"锌褉懈斜谢懈蟹薪芯 蟹邪 {{count}} 褉芯泻褨胁\",\n    },\n  }),\n\n  xYears: buildLocalizeTokenFn({\n    regular: {\n      singularNominative: \"{{count}} 褉褨泻\",\n      singularGenitive: \"{{count}} 褉芯泻懈\",\n      pluralGenitive: \"{{count}} 褉芯泻褨胁\",\n    },\n  }),\n\n  overXYears: buildLocalizeTokenFn({\n    regular: {\n      singularNominative: \"斜褨谢褜褕械 {{count}} 褉芯泻褍\",\n      singularGenitive: \"斜褨谢褜褕械 {{count}} 褉芯泻褨胁\",\n      pluralGenitive: \"斜褨谢褜褕械 {{count}} 褉芯泻褨胁\",\n    },\n    future: {\n      singularNominative: \"斜褨谢褜褕械, 薪褨卸 蟹邪 {{count}} 褉褨泻\",\n      singularGenitive: \"斜褨谢褜褕械, 薪褨卸 蟹邪 {{count}} 褉芯泻懈\",\n      pluralGenitive: \"斜褨谢褜褕械, 薪褨卸 蟹邪 {{count}} 褉芯泻褨胁\",\n    },\n  }),\n\n  almostXYears: buildLocalizeTokenFn({\n    regular: {\n      singularNominative: \"屑邪泄卸械 {{count}} 褉褨泻\",\n      singularGenitive: \"屑邪泄卸械 {{count}} 褉芯泻懈\",\n      pluralGenitive: \"屑邪泄卸械 {{count}} 褉芯泻褨胁\",\n    },\n    future: {\n      singularNominative: \"屑邪泄卸械 蟹邪 {{count}} 褉褨泻\",\n      singularGenitive: \"屑邪泄卸械 蟹邪 {{count}} 褉芯泻懈\",\n      pluralGenitive: \"屑邪泄卸械 蟹邪 {{count}} 褉芯泻褨胁\",\n    },\n  }),\n};\n\nexport const formatDistance = (token, count, options) => {\n  options = options || {};\n\n  return formatDistanceLocale[token](count, options);\n};\n","import { buildFormatLongFn } from \"../../_lib/buildFormatLongFn.js\";\n\nconst dateFormats = {\n  full: \"EEEE, do MMMM y '褉.'\",\n  long: \"do MMMM y '褉.'\",\n  medium: \"d MMM y '褉.'\",\n  short: \"dd.MM.y\",\n};\n\nconst timeFormats = {\n  full: \"H:mm:ss zzzz\",\n  long: \"H:mm:ss z\",\n  medium: \"H:mm:ss\",\n  short: \"H:mm\",\n};\n\nconst dateTimeFormats = {\n  full: \"{{date}} '芯' {{time}}\",\n  long: \"{{date}} '芯' {{time}}\",\n  medium: \"{{date}}, {{time}}\",\n  short: \"{{date}}, {{time}}\",\n};\n\nexport const formatLong = {\n  date: buildFormatLongFn({\n    formats: dateFormats,\n    defaultWidth: \"full\",\n  }),\n\n  time: buildFormatLongFn({\n    formats: timeFormats,\n    defaultWidth: \"full\",\n  }),\n\n  dateTime: buildFormatLongFn({\n    formats: dateTimeFormats,\n    defaultWidth: \"full\",\n  }),\n};\n","import { isSameWeek } from \"../../../isSameWeek.js\";\nimport { toDate } from \"../../../toDate.js\";\n\nconst accusativeWeekdays = [\n  \"薪械写褨谢褞\",\n  \"锌芯薪械写褨谢芯泻\",\n  \"胁褨胁褌芯褉芯泻\",\n  \"褋械褉械写褍\",\n  \"褔械褌胁械褉\",\n  \"锌鈥櫻徰傂叫秆喲嶾",\n  \"褋褍斜芯褌褍\",\n];\n\nfunction lastWeek(day) {\n  const weekday = accusativeWeekdays[day];\n\n  switch (day) {\n    case 0:\n    case 3:\n    case 5:\n    case 6:\n      return \"'褍 屑懈薪褍谢褍 \" + weekday + \" 芯' p\";\n    case 1:\n    case 2:\n    case 4:\n      return \"'褍 屑懈薪褍谢懈泄 \" + weekday + \" 芯' p\";\n  }\n}\n\nfunction thisWeek(day) {\n  const weekday = accusativeWeekdays[day];\n\n  return \"'褍 \" + weekday + \" 芯' p\";\n}\n\nfunction nextWeek(day) {\n  const weekday = accusativeWeekdays[day];\n\n  switch (day) {\n    case 0:\n    case 3:\n    case 5:\n    case 6:\n      return \"'褍 薪邪褋褌褍锌薪褍 \" + weekday + \" 芯' p\";\n    case 1:\n    case 2:\n    case 4:\n      return \"'褍 薪邪褋褌褍锌薪懈泄 \" + weekday + \" 芯' p\";\n  }\n}\n\nconst lastWeekFormat = (dirtyDate, baseDate, options) => {\n  const date = toDate(dirtyDate);\n  const day = date.getDay();\n\n  if (isSameWeek(date, baseDate, options)) {\n    return thisWeek(day);\n  } else {\n    return lastWeek(day);\n  }\n};\n\nconst nextWeekFormat = (dirtyDate, baseDate, options) => {\n  const date = toDate(dirtyDate);\n  const day = date.getDay();\n  if (isSameWeek(date, baseDate, options)) {\n    return thisWeek(day);\n  } else {\n    return nextWeek(day);\n  }\n};\n\nconst formatRelativeLocale = {\n  lastWeek: lastWeekFormat,\n  yesterday: \"'胁褔芯褉邪 芯' p\",\n  today: \"'褋褜芯谐芯写薪褨 芯' p\",\n  tomorrow: \"'蟹邪胁褌褉邪 芯' p\",\n  nextWeek: nextWeekFormat,\n  other: \"P\",\n};\n\nexport const formatRelative = (token, date, baseDate, options) => {\n  const format = formatRelativeLocale[token];\n\n  if (typeof format === \"function\") {\n    return format(date, baseDate, options);\n  }\n\n  return format;\n};\n","import { buildLocalizeFn } from \"../../_lib/buildLocalizeFn.js\";\n\nconst eraValues = {\n  narrow: [\"写芯 薪.械.\", \"薪.械.\"],\n  abbreviated: [\"写芯 薪. 械.\", \"薪. 械.\"],\n  wide: [\"写芯 薪邪褕芯褩 械褉懈\", \"薪邪褕芯褩 械褉懈\"],\n};\n\nconst quarterValues = {\n  narrow: [\"1\", \"2\", \"3\", \"4\"],\n  abbreviated: [\"1-泄 泻胁.\", \"2-泄 泻胁.\", \"3-泄 泻胁.\", \"4-泄 泻胁.\"],\n  wide: [\"1-泄 泻胁邪褉褌邪谢\", \"2-泄 泻胁邪褉褌邪谢\", \"3-泄 泻胁邪褉褌邪谢\", \"4-泄 泻胁邪褉褌邪谢\"],\n};\n\nconst monthValues = {\n  // 袛小孝校 3582:2013\n  narrow: [\"小\", \"袥\", \"袘\", \"袣\", \"孝\", \"效\", \"袥\", \"小\", \"袙\", \"袞\", \"袥\", \"袚\"],\n  abbreviated: [\n    \"褋褨褔.\",\n    \"谢褞褌.\",\n    \"斜械褉械蟹.\",\n    \"泻胁褨褌.\",\n    \"褌褉邪胁.\",\n    \"褔械褉胁.\",\n    \"谢懈锌.\",\n    \"褋械褉锌.\",\n    \"胁械褉械褋.\",\n    \"卸芯胁褌.\",\n    \"谢懈褋褌芯锌.\",\n    \"谐褉褍写.\",\n  ],\n\n  wide: [\n    \"褋褨褔械薪褜\",\n    \"谢褞褌懈泄\",\n    \"斜械褉械蟹械薪褜\",\n    \"泻胁褨褌械薪褜\",\n    \"褌褉邪胁械薪褜\",\n    \"褔械褉胁械薪褜\",\n    \"谢懈锌械薪褜\",\n    \"褋械褉锌械薪褜\",\n    \"胁械褉械褋械薪褜\",\n    \"卸芯胁褌械薪褜\",\n    \"谢懈褋褌芯锌邪写\",\n    \"谐褉褍写械薪褜\",\n  ],\n};\n\nconst formattingMonthValues = {\n  narrow: [\"小\", \"袥\", \"袘\", \"袣\", \"孝\", \"效\", \"袥\", \"小\", \"袙\", \"袞\", \"袥\", \"袚\"],\n  abbreviated: [\n    \"褋褨褔.\",\n    \"谢褞褌.\",\n    \"斜械褉械蟹.\",\n    \"泻胁褨褌.\",\n    \"褌褉邪胁.\",\n    \"褔械褉胁.\",\n    \"谢懈锌.\",\n    \"褋械褉锌.\",\n    \"胁械褉械褋.\",\n    \"卸芯胁褌.\",\n    \"谢懈褋褌芯锌.\",\n    \"谐褉褍写.\",\n  ],\n\n  wide: [\n    \"褋褨褔薪褟\",\n    \"谢褞褌芯谐芯\",\n    \"斜械褉械蟹薪褟\",\n    \"泻胁褨褌薪褟\",\n    \"褌褉邪胁薪褟\",\n    \"褔械褉胁薪褟\",\n    \"谢懈锌薪褟\",\n    \"褋械褉锌薪褟\",\n    \"胁械褉械褋薪褟\",\n    \"卸芯胁褌薪褟\",\n    \"谢懈褋褌芯锌邪写邪\",\n    \"谐褉褍写薪褟\",\n  ],\n};\n\nconst dayValues = {\n  narrow: [\"袧\", \"袩\", \"袙\", \"小\", \"效\", \"袩\", \"小\"],\n  short: [\"薪写\", \"锌薪\", \"胁褌\", \"褋褉\", \"褔褌\", \"锌褌\", \"褋斜\"],\n  abbreviated: [\"薪械写\", \"锌芯薪\", \"胁褨胁\", \"褋械褉\", \"褔褌胁\", \"锌褌薪\", \"褋褍斜\"],\n  wide: [\n    \"薪械写褨谢褟\",\n    \"锌芯薪械写褨谢芯泻\",\n    \"胁褨胁褌芯褉芯泻\",\n    \"褋械褉械写邪\",\n    \"褔械褌胁械褉\",\n    \"锌鈥櫻徰傂叫秆喲廫",\n    \"褋褍斜芯褌邪\",\n  ],\n};\n\nconst dayPeriodValues = {\n  narrow: {\n    am: \"袛袩\",\n    pm: \"袩袩\",\n    midnight: \"锌褨胁薪.\",\n    noon: \"锌芯谢.\",\n    morning: \"褉邪薪芯泻\",\n    afternoon: \"写械薪褜\",\n    evening: \"胁械褔.\",\n    night: \"薪褨褔\",\n  },\n  abbreviated: {\n    am: \"袛袩\",\n    pm: \"袩袩\",\n    midnight: \"锌褨胁薪.\",\n    noon: \"锌芯谢.\",\n    morning: \"褉邪薪芯泻\",\n    afternoon: \"写械薪褜\",\n    evening: \"胁械褔.\",\n    night: \"薪褨褔\",\n  },\n  wide: {\n    am: \"袛袩\",\n    pm: \"袩袩\",\n    midnight: \"锌褨胁薪褨褔\",\n    noon: \"锌芯谢褍写械薪褜\",\n    morning: \"褉邪薪芯泻\",\n    afternoon: \"写械薪褜\",\n    evening: \"胁械褔褨褉\",\n    night: \"薪褨褔\",\n  },\n};\n\nconst formattingDayPeriodValues = {\n  narrow: {\n    am: \"袛袩\",\n    pm: \"袩袩\",\n    midnight: \"锌褨胁薪.\",\n    noon: \"锌芯谢.\",\n    morning: \"褉邪薪泻褍\",\n    afternoon: \"写薪褟\",\n    evening: \"胁械褔.\",\n    night: \"薪芯褔褨\",\n  },\n  abbreviated: {\n    am: \"袛袩\",\n    pm: \"袩袩\",\n    midnight: \"锌褨胁薪.\",\n    noon: \"锌芯谢.\",\n    morning: \"褉邪薪泻褍\",\n    afternoon: \"写薪褟\",\n    evening: \"胁械褔.\",\n    night: \"薪芯褔褨\",\n  },\n  wide: {\n    am: \"袛袩\",\n    pm: \"袩袩\",\n    midnight: \"锌褨胁薪褨褔\",\n    noon: \"锌芯谢褍写械薪褜\",\n    morning: \"褉邪薪泻褍\",\n    afternoon: \"写薪褟\",\n    evening: \"胁械褔.\",\n    night: \"薪芯褔褨\",\n  },\n};\n\nconst ordinalNumber = (dirtyNumber, options) => {\n  const unit = String(options?.unit);\n  const number = Number(dirtyNumber);\n  let suffix;\n\n  if (unit === \"date\") {\n    if (number === 3 || number === 23) {\n      suffix = \"-褦\";\n    } else {\n      suffix = \"-械\";\n    }\n  } else if (unit === \"minute\" || unit === \"second\" || unit === \"hour\") {\n    suffix = \"-邪\";\n  } else {\n    suffix = \"-泄\";\n  }\n\n  return number + suffix;\n};\n\nexport const localize = {\n  ordinalNumber,\n\n  era: buildLocalizeFn({\n    values: eraValues,\n    defaultWidth: \"wide\",\n  }),\n\n  quarter: buildLocalizeFn({\n    values: quarterValues,\n    defaultWidth: \"wide\",\n    argumentCallback: (quarter) => quarter - 1,\n  }),\n\n  month: buildLocalizeFn({\n    values: monthValues,\n    defaultWidth: \"wide\",\n    formattingValues: formattingMonthValues,\n    defaultFormattingWidth: \"wide\",\n  }),\n\n  day: buildLocalizeFn({\n    values: dayValues,\n    defaultWidth: \"wide\",\n  }),\n\n  dayPeriod: buildLocalizeFn({\n    values: dayPeriodValues,\n    defaultWidth: \"any\",\n    formattingValues: formattingDayPeriodValues,\n    defaultFormattingWidth: \"wide\",\n  }),\n};\n","import { buildMatchFn } from \"../../_lib/buildMatchFn.js\";\nimport { buildMatchPatternFn } from \"../../_lib/buildMatchPatternFn.js\";\n\nconst matchOrdinalNumberPattern = /^(\\d+)(-?(械|泄|褦|邪|褟))?/i;\nconst parseOrdinalNumberPattern = /\\d+/i;\n\nconst matchEraPatterns = {\n  narrow: /^((写芯 )?薪\\.?\\s?械\\.?)/i,\n  abbreviated: /^((写芯 )?薪\\.?\\s?械\\.?)/i,\n  wide: /^(写芯 薪邪褕芯褩 械褉懈|薪邪褕芯褩 械褉懈|薪邪褕邪 械褉邪)/i,\n};\n\nconst parseEraPatterns = {\n  any: [/^写/i, /^薪/i],\n};\n\nconst matchQuarterPatterns = {\n  narrow: /^[1234]/i,\n  abbreviated: /^[1234](-?[懈褨]?泄?)? 泻胁.?/i,\n  wide: /^[1234](-?[懈褨]?泄?)? 泻胁邪褉褌邪谢/i,\n};\n\nconst parseQuarterPatterns = {\n  any: [/1/i, /2/i, /3/i, /4/i],\n};\n\nconst matchMonthPatterns = {\n  narrow: /^[褋谢斜泻褌褔胁卸谐]/i,\n  abbreviated:\n    /^(褋褨褔|谢褞褌|斜械褉(械蟹)?|泻胁褨褌|褌褉邪胁|褔械褉胁|谢懈锌|褋械褉锌|胁械褉(械褋)?|卸芯胁褌|谢懈褋(褌芯锌)?|谐褉褍写)\\.?/i,\n  wide: /^(褋褨褔械薪褜|褋褨褔薪褟|谢褞褌懈泄|谢褞褌芯谐芯|斜械褉械蟹械薪褜|斜械褉械蟹薪褟|泻胁褨褌械薪褜|泻胁褨褌薪褟|褌褉邪胁械薪褜|褌褉邪胁薪褟|褔械褉胁薪褟|褔械褉胁械薪褜|谢懈锌械薪褜|谢懈锌薪褟|褋械褉锌械薪褜|褋械褉锌薪褟|胁械褉械褋械薪褜|胁械褉械褋薪褟|卸芯胁褌械薪褜|卸芯胁褌薪褟|谢懈褋褌芯锌邪写[邪]?|谐褉褍写械薪褜|谐褉褍写薪褟)/i,\n};\n\nconst parseMonthPatterns = {\n  narrow: [\n    /^褋/i,\n    /^谢/i,\n    /^斜/i,\n    /^泻/i,\n    /^褌/i,\n    /^褔/i,\n    /^谢/i,\n    /^褋/i,\n    /^胁/i,\n    /^卸/i,\n    /^谢/i,\n    /^谐